const staticData = $getWorkflowStaticData('global');
const body = $input.first().json.body || $input.first().json;
const data = body.data || body;
const key = data.key || {};
const remoteJid = key.remoteJid || '';
const senderName = data.pushName || 'Sin nombre';
const message = data.message || {};
const messageText = message.conversation || (message.extendedTextMessage && message.extendedTextMessage.text) || '';
const messageType = message.imageMessage ? 'image' : (message.audioMessage || message.pttMessage) ? 'audio' : 'text';
const messageId = key.id || '';
const timestamp = Date.now();
if (!staticData.buffers) staticData.buffers = {};
if (!staticData.buffers[remoteJid]) {
  staticData.buffers[remoteJid] = { messages: [], firstMessageAt: timestamp, senderName: senderName };
}
staticData.buffers[remoteJid].messages.push({ id: messageId, text: messageText, type: messageType, timestamp: timestamp, rawMessage: message });
if (senderName && senderName !== 'Sin nombre') staticData.buffers[remoteJid].senderName = senderName;
return [{ json: { remoteJid, senderName: staticData.buffers[remoteJid].senderName, bufferStarted: staticData.buffers[remoteJid].firstMessageAt, messageCount: staticData.buffers[remoteJid].messages.length, latestMessage: messageText, messageType } }];

const staticData = $getWorkflowStaticData('global');
const remoteJid = $input.first().json.remoteJid;
const senderName = $input.first().json.senderName || 'Sin nombre';
if (!staticData.buffers || !staticData.buffers[remoteJid]) {
  return [{ json: { remoteJid, senderName, combinedText: '', messages: [], messageCount: 0, hasAudio: false, hasImage: false, audioMessageIds: [], imageMessageIds: [] } }];
}
const buffer = staticData.buffers[remoteJid];
const messages = buffer.messages || [];
const combinedText = messages.filter(m => m.text && m.text.trim()).map(m => m.text).join('\n');
const hasAudio = messages.some(m => m.type === 'audio');
const hasImage = messages.some(m => m.type === 'image');
const audioMessageIds = messages.filter(m => m.type === 'audio').map(m => m.id);
const imageMessageIds = messages.filter(m => m.type === 'image').map(m => m.id);
const finalSenderName = buffer.senderName || senderName;
delete staticData.buffers[remoteJid];
return [{ json: { remoteJid, senderName: finalSenderName, combinedText, messages, messageCount: messages.length, hasAudio, hasImage, audioMessageIds, imageMessageIds, collectedAt: Date.now() } }];

const items = $input.all();
const contactData = $('Juntar Resultados').first().json;
const remoteJid = contactData.remoteJid;
const senderName = contactData.senderName;
const combinedText = contactData.combinedText;
const hasAudio = contactData.hasAudio;
const hasImage = contactData.hasImage;
const audioTranscription = contactData.audioTranscription || '';
const imageAnalysis = contactData.imageAnalysis || '';
const messageCount = contactData.messageCount;

const httpResponse = items[0].json;
let historialRaw = [];
if (Array.isArray(httpResponse)) {
  historialRaw = httpResponse;
} else if (httpResponse.messages && httpResponse.messages.records) {
  historialRaw = httpResponse.messages.records;
} else if (Array.isArray(httpResponse.data)) {
  historialRaw = httpResponse.data;
}

const ZWS = '\u200B';
const ANGIE_WINDOW_MS = 30 * 60 * 1000;
const now = Date.now();
let angieReplied = false;
let lastAngieMessage = '';
const formattedHistory = [];
const seenKeys = new Set();

for (const msg of historialRaw) {
  const keyId = msg.key && msg.key.id;
  if (keyId && seenKeys.has(keyId)) continue;
  if (keyId) seenKeys.add(keyId);

  const isFromMe = msg.key && msg.key.fromMe === true;
  const messageText = (msg.message && msg.message.conversation) ||
    (msg.message && msg.message.extendedTextMessage && msg.message.extendedTextMessage.text) || '';
  const timestamp = (msg.messageTimestamp || 0) * 1000;
  const isRecent = (now - timestamp) < ANGIE_WINDOW_MS;
  const sender = isFromMe ? 'Angie/Bot' : 'Cliente';

  if (messageText) formattedHistory.push(sender + ': ' + messageText);

  if (isFromMe && messageText && !messageText.startsWith(ZWS) && isRecent) {
    angieReplied = true;
    lastAngieMessage = messageText;
  }
}

return [{ json: {
  remoteJid, senderName, combinedText,
  hasAudio, hasImage, audioTranscription, imageAnalysis,
  angieReplied, lastAngieMessage,
  chatHistory: formattedHistory.slice(-20).join('\n'),
  messageCount
}}];

const contactData = $('Angie Ya Respondio?').first().json;
const remoteJid = contactData.remoteJid || '';
const senderName = contactData.senderName || '';
const combinedText = contactData.combinedText || '';
const hasAudio = contactData.hasAudio || false;
const hasImage = contactData.hasImage || false;
const audioTranscription = contactData.audioTranscription || '';
const imageAnalysis = contactData.imageAnalysis || '';
const chatHistory = contactData.chatHistory || '';
const messageCount = contactData.messageCount || 0;

let activeOrders = 'Sin pedidos activos';
try {
  const pedidosItems = $('Buscar Pedidos Activos').all();
  const found = pedidosItems
    .map(i => i.json)
    .filter(p => p && remoteJid && remoteJid.includes(p.telefono_cliente));
  if (found.length > 0) {
    activeOrders = found.map(p =>
      'Pedido: ' + (p.producto||'N/A') + ' | Estado: ' + (p.estado||'N/A') + ' | Entrega: ' + (p.fecha_entrega||'N/A')
    ).join('\n');
  }
} catch(e) { activeOrders = 'No se pudo consultar pedidos'; }

let catalogSummary = 'Catalogo no disponible';
try {
  const catItems = $('Cargar Catalogo').all();
  const disp = catItems
    .map(i => i.json)
    .filter(p => p && p.disponible !== 'no');
  if (disp.length > 0) {
    catalogSummary = disp.map(p =>
      '- ' + (p.nombre||'N/A') + ': ' + (p.precio||'N/A') + ' (' + (p.categoria||'general') + ') - ' + (p.descripcion||'') + ' | IMG: ' + (p.imagen_url||'sin imagen')
    ).join('\n');
  }
} catch(e) { catalogSummary = 'No se pudo cargar catalogo'; }

const now = new Date();
const fechaHora = now.toLocaleDateString('es-CO', {
  year:'numeric', month:'2-digit', day:'2-digit',
  hour:'2-digit', minute:'2-digit', timeZone:'America/Bogota'
});

return [{ json: {
  remoteJid, senderName, combinedText,
  hasAudio, hasImage, audioTranscription, imageAnalysis,
  angieReplied: contactData.angieReplied || false,
  chatHistory,
  hasActiveOrder: activeOrders !== 'Sin pedidos activos' && activeOrders !== 'No se pudo consultar pedidos',
  activeOrderDetails: activeOrders,
  catalogSummary,
  fechaHora,
  messageCount
}}];

try {
  const responseText = $input.first().json.response || '';
  const remoteJid = $input.first().json.remoteJid || '';
  const senderName = $input.first().json.senderName || '';

  // Try to parse JSON response
  let parsedResponse = {};
  try {
    parsedResponse = JSON.parse(responseText);
  } catch (e) {
    // If not valid JSON, try to extract JSON from response
    const jsonMatch = responseText.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      parsedResponse = JSON.parse(jsonMatch[0]);
    }
  }

  // Ensure all required fields exist
  const result = {
    action: parsedResponse.action || 'reply',
    messages: parsedResponse.messages || [],
    image_messages: parsedResponse.image_messages || [],
    send_images: parsedResponse.send_images || [],
    escalate_reason: parsedResponse.escalate_reason || null,
    escalate_to: parsedResponse.escalate_to || null,
    detected_intent: parsedResponse.detected_intent || 'personalizado',
    notify_angie: parsedResponse.notify_angie || false,
    angie_summary: parsedResponse.angie_summary || '',
    register_lead: parsedResponse.register_lead || false,
    lead_data: parsedResponse.lead_data || {
      nombre_cliente: '',
      telefono_cliente: '',
      producto: '',
      total: '',
      estado: 'interesado',
      nombre_recibe: '',
      telefono_recibe: '',
      direccion_entrega: '',
      fecha_entrega: '',
      hora_entrega: '',
      mensaje_tarjeta: '',
      adiciones: '',
      domicilio: ''
    },
    pause_bot: parsedResponse.pause_bot || false,
    remoteJid: remoteJid,
    senderName: senderName
  };

  return [{ json: result }];
} catch (error) {
  return [{ json: { error: error.message, remoteJid: $input.first().json.remoteJid } }];
}

const ZWS = '\u200B';
const data = $input.first().json;
const remoteJid = data.remoteJid;
const senderName = data.senderName || 'Cliente';
const messages = data.messages || [];
const reason = data.escalate_reason || 'Requiere atencion personal';
const EVOLUTION_URL = $env.EVOLUTION_API_URL;
const EVOLUTION_KEY = $env.EVOLUTION_API_KEY;
const INSTANCE = $env.EVOLUTION_INSTANCE;
const ANGIE_PHONE = $env.ANGIE_PHONE;

try {
  await $helpers.httpRequest({
    method: 'POST',
    url: EVOLUTION_URL + '/message/sendText/' + INSTANCE,
    headers: { 'apikey': EVOLUTION_KEY, 'Content-Type': 'application/json' },
    body: JSON.stringify({
      number: ANGIE_PHONE,
      text: '\u26a0\ufe0f ESCALACION BOT\n\nCliente: ' + senderName + '\nNumero: ' + remoteJid + '\nRazon: ' + reason
    })
  });
} catch(e) {}

if (messages.length > 0) {
  try {
    await $helpers.httpRequest({
      method: 'POST',
      url: EVOLUTION_URL + '/message/sendPresence/' + INSTANCE,
      headers: { 'apikey': EVOLUTION_KEY, 'Content-Type': 'application/json' },
      body: JSON.stringify({ number: remoteJid, delay: 1000, presence: 'composing' })
    });
    await new Promise(r => setTimeout(r, 2000));
    await $helpers.httpRequest({
      method: 'POST',
      url: EVOLUTION_URL + '/message/sendText/' + INSTANCE,
      headers: { 'apikey': EVOLUTION_KEY, 'Content-Type': 'application/json' },
      body: JSON.stringify({ number: remoteJid, text: ZWS + messages[0] })
    });
  } catch(e) {}
}

return [{ json: { action: 'escalate', remoteJid, reason } }];

const EVOLUTION_URL = $env.EVOLUTION_API_URL;
const EVOLUTION_KEY = $env.EVOLUTION_API_KEY;
const INSTANCE = $env.EVOLUTION_INSTANCE;
const ANGIE_PHONE = $env.ANGIE_PHONE;

const errorMsg = $json.execution?.error?.message || $json.error?.message || 'Error desconocido';
const workflowName = $json.workflow?.name || 'Duquesa Bot';

try {
  await $helpers.httpRequest({
    method: 'POST',
    url: EVOLUTION_URL + '/message/sendText/' + INSTANCE,
    headers: { 'apikey': EVOLUTION_KEY, 'Content-Type': 'application/json' },
    body: JSON.stringify({
      number: ANGIE_PHONE,
      text: '\u274c ERROR BOT DUQUESA\n\nWorkflow: ' + workflowName + '\nError: ' + String(errorMsg).substring(0, 500)
    })
  });
} catch(e) {}

return [{ json: { notified: true, error: errorMsg } }];

const ZWS = '\u200B';
const data = $input.first().json;
const messages = data.messages || [];
const remoteJid = data.remoteJid;

if (messages.length === 0) {
  return [{ json: { remoteJid, text: '', empty: true } }];
}

return messages.map(msg => ({
  json: {
    remoteJid,
    text: ZWS + msg
  }
}));

const data = $input.first().json;
const images = data.send_images || [];
const remoteJid = data.remoteJid;

if (images.length === 0) {
  return [{ json: { remoteJid, imageUrl: '', empty: true } }];
}

return images.map(url => ({
  json: {
    remoteJid,
    imageUrl: url
  }
}));

const input = $input.first().json;
const mediaData = input.data;
const base64 = mediaData.base64 || '';
const mimetype = mediaData.mimetype || 'image/jpeg';

const binaryData = Buffer.from(base64, 'base64');

return [{
  json: {
    ...mediaData
  },
  binary: {
    image: {
      data: base64,
      mimeType: mimetype,
      fileName: mediaData.fileName || 'image.jpg'
    }
  }
}];

const input = $input.first().json;
const remoteJid = input.remoteJid;
const senderName = input.senderName;
const combinedText = input.combinedText || '';
const messageCount = input.messageCount;
const messages = input.messages || [];

let hasAudio = false;
let hasImage = false;
let imageMessageId = '';
let audioMessageId = '';
let imageCaption = '';

for (const msg of messages) {
  if (msg.type === 'image') {
    hasImage = true;
    imageMessageId = msg.id;
    imageCaption = (msg.rawMessage && msg.rawMessage.imageMessage && msg.rawMessage.imageMessage.caption) || '';
  }
  if (msg.type === 'audio' || msg.type === 'ptt') {
    hasAudio = true;
    audioMessageId = msg.id;
  }
}

// Si hay caption de imagen, agregarlo al texto
const fullText = imageCaption ? (combinedText ? combinedText + '\n' + imageCaption : imageCaption) : combinedText;

return [{
  json: {
    remoteJid,
    senderName,
    combinedText: fullText,
    messageCount,
    hasImage,
    hasAudio,
    imageMessageId,
    audioMessageId
  }
}];

const infoData = $('Info Multimedia').first().json;

let imageAnalysis = '';
try {
  const anthropicOutput = $('Analyze image').first().json;
  imageAnalysis = anthropicOutput.text || anthropicOutput.content || JSON.stringify(anthropicOutput);
} catch(e) {}

let audioTranscription = '';
try {
  const whisperOutput = $('Transcribir Audio').first().json;
  audioTranscription = whisperOutput.text || '';
} catch(e) {}

return [{
  json: {
    remoteJid: infoData.remoteJid,
    senderName: infoData.senderName,
    combinedText: infoData.combinedText,
    messageCount: infoData.messageCount,
    hasAudio: infoData.hasAudio,
    hasImage: infoData.hasImage,
    audioTranscription: audioTranscription,
    imageAnalysis: imageAnalysis
  }
}];

const input = $input.first().json;
const mediaData = input.data;
const base64 = mediaData.base64 || '';
const mimetype = mediaData.mimetype || 'audio/ogg';

return [{
  json: {
    ...mediaData
  },
  binary: {
    data: {
      data: base64,
      mimeType: mimetype,
      fileName: mediaData.fileName || 'audio.ogg'
    }
  }
}];

const data = $input.first().json;
const imageMessages = data.image_messages || [];
const remoteJid = data.remoteJid;

if (imageMessages.length === 0) {
  return [{ json: { remoteJid, imageUrl: '', caption: '', empty: true } }];
}

return imageMessages.map(item => ({
  json: {
    remoteJid,
    imageUrl: item.image,
    caption: item.caption || ''
  }
}));
